-- Scriptures table: stores daily devotionals
CREATE TABLE IF NOT EXISTS scriptures (
    id TEXT PRIMARY KEY,
    reference TEXT NOT NULL,
    text TEXT NOT NULL,
    version TEXT DEFAULT 'NKJV',
    category TEXT,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP
);

