INSERT INTO events (id, title, date, time, venue, description, image_url, category, is_featured, is_special, event_status) VALUES
('0188b8e0-1234-7abc-8def-000000000001', 'Keepers of the Flame', '2026-06-27T09:00:00Z', '9:00 AM', 'AGCM Basement, Ayeduase', 'Join us for a powerful time of worship, the word, and impartation. This is our special anointing service spanning two days to equip you for the semester.', '/images/Laptop.jpg', 'Service', 1, 0, 'confirmed'),
('0188b8e0-1234-7abc-8def-000000000002', 'Campus Prayer Walk', '2026-06-19T17:00:00Z', '5:00 PM - 7:00 PM', 'Starts at University Square', 'We are taking the gospel to the streets! Join us as we walk and pray through the campus, interceding for students and lecturers.', '/images/event-prayer.jpg', 'Outreach', 1, 0, 'confirmed'),
('0188b8e0-1234-7abc-8def-000000000003', 'Youth Impact Night', '2026-06-26T18:00:00Z', '6:00 PM - 9:00 PM', 'Student Center, Room A', 'An evening of music, spoken word, and a relevant message tailored for young adults navigating campus life.', '/images/event-youth.jpg', 'Youth', 1, 0, 'confirmed'),
('0188b8e0-1234-7abc-8def-000000000004', 'Mid-week Bible Study', '2026-06-17T18:30:00Z', '6:30 PM - 8:00 PM', 'Chapel Annexe', 'Dig deeper into the Word of God. We are currently studying the book of Romans. Interactive Q&A session included.', '/images/event-bible.jpg', 'Teaching', 0, 0, 'confirmed'),
('0188b8e0-1234-7abc-8def-000000000005', 'Freshers'' Akwaaba Bash', '2026-07-05T16:00:00Z', '4:00 PM - 8:00 PM', 'Campus Gardens', 'A special welcome event for all incoming students. Free food, games, music, and an opportunity to meet the FGCM family.', '/images/event-welcome.jpg', 'Social', 0, 0, 'confirmed');
INSERT INTO products (id, name, price, description, image_url, sizes_json, category, is_featured) VALUES
('0188b8e0-1234-7abc-8def-000000000010', 'FGCM Classic Logo T-Shirt', 85, 'Show your campus pride with our classic FGCM logo t-shirt. Made from 100% premium cotton for maximum comfort during services and casual days on campus.', '/images/merch-tshirt-black.jpg', '["S", "M", "L", "XL", "XXL"]', 'T-Shirts', 1),
('0188b8e0-1234-7abc-8def-000000000011', 'Premium ''Faith'' Hoodie', 150, 'Stay warm during late-night study sessions or early morning prayers. Features a minimalist ''FAITH'' typography design and a soft fleece interior.', '/images/merch-hoodie.jpg', '["S", "M", "L", "XL"]', 'Hoodies', 1),
('0188b8e0-1234-7abc-8def-000000000012', 'Campus Ministry Dad Hat', 45, 'An adjustable, embroidered cap perfect for sunny days or bad hair days. Simple, stylish, and comfortable.', '/images/merch-cap.jpg', '["One Size"]', 'Accessories', 1),
('0188b8e0-1234-7abc-8def-000000000013', 'Grace Over Grind Oversized Tee', 95, 'Trendy oversized fit t-shirt featuring the popular ''Grace Over Grind'' manifesto on the back. Heavyweight cotton for a premium streetwear feel.', '/images/merch-oversized.jpg', '["M", "L", "XL"]', 'T-Shirts', 1),
('0188b8e0-1234-7abc-8def-000000000014', 'FGCM Custom Journal', 35, 'Take sermon notes in style. A faux-leather bound journal with 200 lined pages and a ribbon bookmark.', '/images/merch-journal.jpg', '["Standard"]', 'Accessories', 0),
('0188b8e0-1234-7abc-8def-000000000015', 'Worship Team Zip-Up', 130, 'Lightweight zip-up hoodie, perfect for layering. Features the FGCM emblem on the left chest.', '/images/merch-zipup.jpg', '["S", "M", "L", "XL", "XXL"]', 'Hoodies', 0);
INSERT INTO scriptures (id, reference, text, version, category) VALUES
('0188b8e0-1234-7abc-8def-100000000001', 'Jeremiah 29:11', 'For I know the thoughts that I think toward you, says the LORD, thoughts of peace and not of evil, to give you a future and a hope.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-100000000002', 'Philippians 4:13', 'I can do all things through Christ who strengthens me.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000003', 'Proverbs 3:5-6', 'Trust in the LORD with all your heart, And lean not on your own understanding; In all your ways acknowledge Him, And He shall direct your paths.', 'NKJV', 'Guidance'),
('0188b8e0-1234-7abc-8def-100000000004', 'Isaiah 41:10', 'Fear not, for I am with you; Be not dismayed, for I am your God. I will strengthen you, Yes, I will help you, I will uphold you with My righteous right hand.', 'NKJV', 'Encouragement'),
('0188b8e0-1234-7abc-8def-100000000005', 'Romans 8:28', 'And we know that all things work together for good to those who love God, to those who are the called according to His purpose.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000006', 'Joshua 1:9', 'Have I not commanded you? Be strong and of good courage; do not be afraid, nor be dismayed, for the LORD your God is with you wherever you go.', 'NKJV', 'Courage'),
('0188b8e0-1234-7abc-8def-100000000007', 'Matthew 11:28', 'Come to Me, all you who labor and are heavy laden, and I will give you rest.', 'NKJV', 'Rest'),
('0188b8e0-1234-7abc-8def-100000000008', 'Psalm 23:1', 'The LORD is my shepherd; I shall not want.', 'NKJV', 'Provision'),
('0188b8e0-1234-7abc-8def-100000000009', 'Lamentations 3:22-23', 'Through the LORD’s mercies we are not consumed, Because His compassions fail not. They are new every morning; Great is Your faithfulness.', 'NKJV', 'Mercy'),
('0188b8e0-1234-7abc-8def-100000000010', '2 Corinthians 5:17', 'Therefore, if anyone is in Christ, he is a new creation; old things have passed away; behold, all things have become new.', 'NKJV', 'Transformation'),
('0188b8e0-1234-7abc-8def-100000000011', 'Ephesians 2:8-9', 'For by grace you have been saved through faith, and that not of yourselves; it is the gift of God, not of works, lest anyone should boast.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-100000000012', 'Hebrews 11:1', 'Now faith is the substance of things hoped for, the evidence of things not seen.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000013', 'Psalm 46:1', 'God is our refuge and strength, A very present help in trouble.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000014', 'Galatians 5:22-23', 'But the fruit of the Spirit is love, joy, peace, longsuffering, kindness, goodness, faithfulness, gentleness, self-control. Against such there is no law.', 'NKJV', 'Character'),
('0188b8e0-1234-7abc-8def-100000000015', 'John 14:27', 'Peace I leave with you, My peace I give to you; not as the world gives do I give to you. Let not your heart be troubled, neither let it be afraid.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000016', 'Romans 12:2', 'And do not be conformed to this world, but be transformed by the renewing of your mind, that you may prove what is that good and acceptable and perfect will of God.', 'NKJV', 'Transformation'),
('0188b8e0-1234-7abc-8def-100000000017', '1 Corinthians 10:13', 'No temptation has overtaken you except such as is common to man; but God is faithful, who will not allow you to be tempted beyond what you are able...', 'NKJV', 'Perseverance'),
('0188b8e0-1234-7abc-8def-100000000018', 'Isaiah 40:31', 'But those who wait on the LORD Shall renew their strength; They shall mount up with wings like eagles, They shall run and not be weary, They shall walk and not faint.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000019', 'Psalm 119:105', 'Your word is a lamp to my feet And a light to my path.', 'NKJV', 'Guidance'),
('0188b8e0-1234-7abc-8def-100000000020', 'Matthew 6:33', 'But seek first the kingdom of God and His righteousness, and all these things shall be added to you.', 'NKJV', 'Priorities'),
('0188b8e0-1234-7abc-8def-100000000021', '1 Peter 5:7', 'Casting all your care upon Him, for He cares for you.', 'NKJV', 'Comfort'),
('0188b8e0-1234-7abc-8def-100000000022', 'Philippians 4:6-7', 'Be anxious for nothing, but in everything by prayer and supplication, with thanksgiving, let your requests be made known to God...', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000023', 'James 1:2-3', 'My brethren, count it all joy when you fall into various trials, knowing that the testing of your faith produces patience.', 'NKJV', 'Endurance'),
('0188b8e0-1234-7abc-8def-100000000024', 'John 3:16', 'For God so loved the world that He gave His only begotten Son, that whoever believes in Him should not perish but have everlasting life.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000025', 'Romans 5:8', 'But God demonstrates His own love toward us, in that while we were still sinners, Christ died for us.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000026', 'Ephesians 3:20', 'Now to Him who is able to do exceedingly abundantly above all that we ask or think, according to the power that works in us.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000027', 'Zephaniah 3:17', 'The LORD your God in your midst, The Mighty One, will save; He will rejoice over you with gladness, He will quiet you with His love...', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000028', 'Psalm 27:1', 'The LORD is my light and my salvation; Whom shall I fear? The LORD is the strength of my life; Of whom shall I be afraid?', 'NKJV', 'Courage'),
('0188b8e0-1234-7abc-8def-100000000029', 'Micah 6:8', 'He has shown you, O man, what is good; And what does the LORD require of you But to do justly, To love mercy, And to walk humbly with your God?', 'NKJV', 'Obedience'),
('0188b8e0-1234-7abc-8def-100000000030', 'Romans 15:13', 'Now may the God of hope fill you with all joy and peace in believing, that you may abound in hope by the power of the Holy Spirit.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-100000000031', 'Colossians 3:23', 'And whatever you do, do it heartily, as to the Lord and not to men.', 'NKJV', 'Diligence'),
('0188b8e0-1234-7abc-8def-100000000032', '2 Timothy 1:7', 'For God has not given us a spirit of fear, but of power and of love and of a sound mind.', 'NKJV', 'Courage'),
('0188b8e0-1234-7abc-8def-100000000033', 'Hebrews 4:16', 'Let us therefore come boldly to the throne of grace, that we may obtain mercy and find grace to help in time of need.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-100000000034', '1 John 4:18', 'There is no fear in love; but perfect love casts out fear, because fear involves torment. But he who fears has not been made perfect in love.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000035', 'Psalm 34:18', 'The LORD is near to those who have a broken heart, And saves such as have a contrite spirit.', 'NKJV', 'Comfort'),
('0188b8e0-1234-7abc-8def-100000000036', 'Matthew 28:20', 'Teaching them to observe all things that I have commanded you; and lo, I am with you always, even to the end of the age. Amen.', 'NKJV', 'Assurance'),
('0188b8e0-1234-7abc-8def-100000000037', 'John 16:33', 'These things I have spoken to you, that in Me you may have peace. In the world you will have tribulation; but be of good cheer, I have overcome the world.', 'NKJV', 'Victory'),
('0188b8e0-1234-7abc-8def-100000000038', 'Romans 8:38-39', 'For I am persuaded that neither death nor life, nor angels nor principalities nor powers, nor things present nor things to come... shall be able to separate us from the love of God...', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000039', '1 Corinthians 16:14', 'Let all that you do be done with love.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000040', '2 Corinthians 12:9', 'And He said to me, "My grace is sufficient for you, for My strength is made perfect in weakness." Therefore most gladly I will rather boast in my infirmities...', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-100000000041', 'Galatians 2:20', 'I have been crucified with Christ; it is no longer I who live, but Christ lives in me; and the life which I now live in the flesh I live by faith in the Son of God...', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000042', 'Ephesians 6:11', 'Put on the whole armor of God, that you may be able to stand against the wiles of the devil.', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-100000000043', 'Philippians 1:6', 'Being confident of this very thing, that He who has begun a good work in you will complete it until the day of Jesus Christ.', 'NKJV', 'Assurance'),
('0188b8e0-1234-7abc-8def-100000000044', 'Colossians 3:15', 'And let the peace of God rule in your hearts, to which also you were called in one body; and be thankful.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000045', '1 Thessalonians 5:16-18', 'Rejoice always, pray without ceasing, in everything give thanks; for this is the will of God in Christ Jesus for you.', 'NKJV', 'Gratitude'),
('0188b8e0-1234-7abc-8def-100000000046', 'Hebrews 12:1-2', 'Therefore we also, since we are surrounded by so great a cloud of witnesses, let us lay aside every weight, and the sin which so easily ensnares us...', 'NKJV', 'Endurance'),
('0188b8e0-1234-7abc-8def-100000000047', 'James 4:8', 'Draw near to God and He will draw near to you. Cleanse your hands, you sinners; and purify your hearts, you double-minded.', 'NKJV', 'Intimacy'),
('0188b8e0-1234-7abc-8def-100000000048', '1 Peter 2:9', 'But you are a chosen generation, a royal priesthood, a holy nation, His own special people, that you may proclaim the praises of Him who called you out of darkness...', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000049', '1 John 1:9', 'If we confess our sins, He is faithful and just to forgive us our sins and to cleanse us from all unrighteousness.', 'NKJV', 'Forgiveness'),
('0188b8e0-1234-7abc-8def-100000000050', 'Revelation 21:4', 'And God will wipe away every tear from their eyes; there shall be no more death, nor sorrow, nor crying. There shall be no more pain, for the former things have passed away.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-100000000051', 'Psalm 42:11', 'Why are you cast down, O my soul? And why are you disquieted within me? Hope in God; For I shall yet praise Him, The help of my countenance and my God.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-100000000052', 'Isaiah 26:3', 'You will keep him in perfect peace, Whose mind is stayed on You, Because he trusts in You.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000053', 'Proverbs 18:10', 'The name of the LORD is a strong tower; The righteous run to it and are safe.', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-100000000054', '1 Corinthians 13:4-5', 'Love suffers long and is kind; love does not envy; love does not parade itself, is not puffed up; does not behave rudely, does not seek its own...', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000055', 'Matthew 5:14-16', 'You are the light of the world. A city that is set on a hill cannot be hidden. Let your light so shine before men...', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000056', 'Romans 10:9', 'That if you confess with your mouth the Lord Jesus and believe in your heart that God has raised Him from the dead, you will be saved.', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000057', 'Psalm 121:1-2', 'I will lift up my eyes to the hills—From whence comes my help? My help comes from the LORD, Who made heaven and earth.', 'NKJV', 'Provision'),
('0188b8e0-1234-7abc-8def-100000000058', 'Jeremiah 33:3', 'Call to Me, and I will answer you, and show you great and mighty things, which you do not know.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000059', 'Hebrews 13:5', 'Let your conduct be without covetousness; be content with such things as you have. For He Himself has said, "I will never leave you nor forsake you."', 'NKJV', 'Assurance'),
('0188b8e0-1234-7abc-8def-100000000060', 'Galatians 6:9', 'And let us not grow weary while doing good, for in due season we shall reap if we do not lose heart.', 'NKJV', 'Perseverance'),
('0188b8e0-1234-7abc-8def-100000000061', 'Psalm 91:1-2', 'He who dwells in the secret place of the Most High Shall abide under the shadow of the Almighty. I will say of the LORD, "He is my refuge and my fortress..."', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-100000000062', 'Matthew 19:26', 'But Jesus looked at them and said to them, "With men this is impossible, but with God all things are possible."', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000063', 'Ephesians 4:32', 'And be kind to one another, tenderhearted, forgiving one another, even as God in Christ forgave you.', 'NKJV', 'Forgiveness'),
('0188b8e0-1234-7abc-8def-100000000064', 'Psalm 1:1-2', 'Blessed is the man Who walks not in the counsel of the ungodly... But his delight is in the law of the LORD, And in His law he meditates day and night.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-100000000065', 'Colossians 1:13-14', 'He has delivered us from the power of darkness and conveyed us into the kingdom of the Son of His love, in whom we have redemption through His blood...', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000066', 'Proverbs 16:3', 'Commit your works to the LORD, And your thoughts will be established.', 'NKJV', 'Guidance'),
('0188b8e0-1234-7abc-8def-100000000067', 'Psalm 19:14', 'Let the words of my mouth and the meditation of my heart Be acceptable in Your sight, O LORD, my strength and my Redeemer.', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-100000000068', 'Philippians 2:3-4', 'Let nothing be done through selfish ambition or conceit, but in lowliness of mind let each esteem others better than himself.', 'NKJV', 'Humility'),
('0188b8e0-1234-7abc-8def-100000000069', 'Romans 12:12', 'Rejoicing in hope, patient in tribulation, continuing steadfastly in prayer.', 'NKJV', 'Endurance'),
('0188b8e0-1234-7abc-8def-100000000070', 'Lamentations 3:24', '"The LORD is my portion," says my soul, "Therefore I hope in Him!"', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-100000000071', 'Romans 8:31', 'What then shall we say to these things? If God is for us, who can be against us?', 'NKJV', 'Assurance'),
('0188b8e0-1234-7abc-8def-100000000072', 'Isaiah 43:2', 'When you pass through the waters, I will be with you; And through the rivers, they shall not overflow you.', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-100000000073', 'Proverbs 4:23', 'Keep your heart with all diligence, For out of it spring the issues of life.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-100000000074', 'Psalm 118:24', 'This is the day the LORD has made; We will rejoice and be glad in it.', 'NKJV', 'Joy'),
('0188b8e0-1234-7abc-8def-100000000075', 'Matthew 17:20', 'If you have faith as a mustard seed, you will say to this mountain, "Move from here to there," and it will move; and nothing will be impossible for you.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000076', '1 John 5:14', 'Now this is the confidence that we have in Him, that if we ask anything according to His will, He hears us.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000077', 'Hebrews 10:23', 'Let us hold fast the confession of our hope without wavering, for He who promised is faithful.', 'NKJV', 'Faithfulness'),
('0188b8e0-1234-7abc-8def-100000000078', 'Psalm 46:10', 'Be still, and know that I am God; I will be exalted among the nations, I will be exalted in the earth!', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000079', 'Philippians 3:14', 'I press toward the goal for the prize of the upward call of God in Christ Jesus.', 'NKJV', 'Perseverance'),
('0188b8e0-1234-7abc-8def-100000000080', 'Romans 12:1', 'I beseech you therefore, brethren, by the mercies of God, that you present your bodies a living sacrifice, holy, acceptable to God.', 'NKJV', 'Dedication'),
('0188b8e0-1234-7abc-8def-100000000081', '2 Chronicles 7:14', 'If My people who are called by My name will humble themselves, and pray and seek My face, and turn from their wicked ways, then I will hear from heaven...', 'NKJV', 'Repentance'),
('0188b8e0-1234-7abc-8def-100000000082', 'Isaiah 54:17', 'No weapon formed against you shall prosper, And every tongue which rises against you in judgment You shall condemn.', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-100000000083', 'James 1:5', 'If any of you lacks wisdom, let him ask of God, who gives to all liberally and without reproach, and it will be given to him.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-100000000084', 'Proverbs 31:25', 'Strength and honor are her clothing; She shall rejoice in time to come.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000085', 'John 15:5', 'I am the vine, you are the branches. He who abides in Me, and I in him, bears much fruit; for without Me you can do nothing.', 'NKJV', 'Dependence'),
('0188b8e0-1234-7abc-8def-100000000086', '1 Corinthians 15:58', 'Therefore, my beloved brethren, be steadfast, immovable, always abounding in the work of the Lord, knowing that your labor is not in vain in the Lord.', 'NKJV', 'Diligence'),
('0188b8e0-1234-7abc-8def-100000000087', 'Psalm 139:14', 'I will praise You, for I am fearfully and wonderfully made; Marvelous are Your works, And that my soul knows very well.', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000088', 'Ephesians 2:10', 'For we are His workmanship, created in Christ Jesus for good works, which God prepared beforehand that we should walk in them.', 'NKJV', 'Purpose'),
('0188b8e0-1234-7abc-8def-100000000089', 'Romans 6:23', 'For the wages of sin is death, but the gift of God is eternal life in Christ Jesus our Lord.', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000090', 'Galatians 5:1', 'Stand fast therefore in the liberty by which Christ has made us free, and do not be entangled again with a yoke of bondage.', 'NKJV', 'Freedom'),
('0188b8e0-1234-7abc-8def-100000000091', '1 Peter 5:8', 'Be sober, be vigilant; because your adversary the devil walks about like a roaring lion, seeking whom he may devour.', 'NKJV', 'Vigilance'),
('0188b8e0-1234-7abc-8def-100000000092', 'Hebrews 11:6', 'But without faith it is impossible to please Him, for he who comes to God must believe that He is, and that He is a rewarder of those who diligently seek Him.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000093', 'Psalm 51:10', 'Create in me a clean heart, O God, And renew a steadfast spirit within me.', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-100000000094', 'Matthew 11:29-30', 'Take My yoke upon you and learn from Me, for I am gentle and lowly in heart, and you will find rest for your souls. For My yoke is easy and My burden is light.', 'NKJV', 'Rest'),
('0188b8e0-1234-7abc-8def-100000000095', 'John 14:6', 'Jesus said to him, "I am the way, the truth, and the life. No one comes to the Father except through Me."', 'NKJV', 'Truth'),
('0188b8e0-1234-7abc-8def-100000000096', 'Acts 4:12', 'Nor is there salvation in any other, for there is no other name under heaven given among men by which we must be saved.', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000097', 'Romans 1:16', 'For I am not ashamed of the gospel of Christ, for it is the power of God to salvation for everyone who believes.', 'NKJV', 'Courage'),
('0188b8e0-1234-7abc-8def-100000000098', '2 Corinthians 4:16', 'Therefore we do not lose heart. Even though our outward man is perishing, yet the inward man is being renewed day by day.', 'NKJV', 'Renewal'),
('0188b8e0-1234-7abc-8def-100000000099', 'Ephesians 4:2', 'With all lowliness and gentleness, with longsuffering, bearing with one another in love.', 'NKJV', 'Patience'),
('0188b8e0-1234-7abc-8def-10000000100', 'Philippians 4:8', 'Finally, brethren, whatever things are true, whatever things are noble, whatever things are just, whatever things are pure... meditate on these things.', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-10000000101', 'Colossians 3:2', 'Set your mind on things above, not on things on the earth.', 'NKJV', 'Focus'),
('0188b8e0-1234-7abc-8def-10000000102', '1 Timothy 4:12', 'Let no one despise your youth, but be an example to the believers in word, in conduct, in love, in spirit, in faith, in purity.', 'NKJV', 'Leadership'),
('0188b8e0-1234-7abc-8def-10000000103', '2 Timothy 3:16', 'All Scripture is given by inspiration of God, and is profitable for doctrine, for reproof, for correction, for instruction in righteousness.', 'NKJV', 'Truth'),
('0188b8e0-1234-7abc-8def-10000000104', 'Titus 2:11', 'For the grace of God that brings salvation has appeared to all men.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-10000000105', 'Philemon 1:6', 'That the sharing of your faith may become effective by the acknowledgment of every good thing which is in you in Christ Jesus.', 'NKJV', 'Evangelism'),
('0188b8e0-1234-7abc-8def-10000000106', 'Hebrews 13:8', 'Jesus Christ is the same yesterday, today, and forever.', 'NKJV', 'Consistency'),
('0188b8e0-1234-7abc-8def-10000000107', 'James 5:16', 'Confess your trespasses to one another, and pray for one another, that you may be healed. The effective, fervent prayer of a righteous man avails much.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-10000000108', '1 Peter 3:15', 'But sanctify the Lord God in your hearts, and always be ready to give a defense to everyone who asks you a reason for the hope that is in you.', 'NKJV', 'Preparation'),
('0188b8e0-1234-7abc-8def-10000000109', '2 Peter 3:9', 'The Lord is not slack concerning His promise, as some count slackness, but is longsuffering toward us, not willing that any should perish.', 'NKJV', 'Patience'),
('0188b8e0-1234-7abc-8def-10000000110', '1 John 3:18', 'My little children, let us not love in word or in tongue, but in deed and in truth.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-10000000111', 'Jude 1:24', 'Now to Him who is able to keep you from stumbling, And to present you faultless Before the presence of His glory with exceeding joy.', 'NKJV', 'Assurance'),
('0188b8e0-1234-7abc-8def-10000000112', 'Revelation 3:20', 'Behold, I stand at the door and knock. If anyone hears My voice and opens the door, I will come in to him and dine with him, and he with Me.', 'NKJV', 'Invitation'),
('0188b8e0-1234-7abc-8def-10000000113', 'Genesis 1:1', 'In the beginning God created the heavens and the earth.', 'NKJV', 'Creation'),
('0188b8e0-1234-7abc-8def-10000000114', 'Exodus 14:14', 'The LORD will fight for you, and you shall hold your peace.', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-10000000115', 'Leviticus 19:18', 'You shall not take vengeance, nor bear any grudge against the children of your people, but you shall love your neighbor as yourself.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-10000000116', 'Numbers 6:24-26', 'The LORD bless you and keep you; The LORD make His face shine upon you, And be gracious to you; The LORD lift up His countenance upon you, And give you peace.', 'NKJV', 'Blessing'),
('0188b8e0-1234-7abc-8def-10000000117', 'Deuteronomy 31:6', 'Be strong and of good courage, do not fear nor be afraid of them; for the LORD your God, He is the One who goes with you. He will not leave you nor forsake you.', 'NKJV', 'Courage'),
('0188b8e0-1234-7abc-8def-10000000118', 'Joshua 24:15', 'And if it seems evil to you to serve the LORD, choose for yourselves this day whom you will serve... But as for me and my house, we will serve the LORD.', 'NKJV', 'Commitment'),
('0188b8e0-1234-7abc-8def-10000000119', 'Judges 5:31', 'Thus let all Your enemies perish, O LORD! But let those who love Him be like the sun When it comes out in full strength.', 'NKJV', 'Victory'),
('0188b8e0-1234-7abc-8def-10000000120', 'Ruth 1:16', 'But Ruth said: "Entreat me not to leave you, Or to turn back from following after you; For wherever you go, I will go; And wherever you lodge, I will lodge..."', 'NKJV', 'Loyalty'),
('0188b8e0-1234-7abc-8def-10000000121', '1 Samuel 16:7', 'For the LORD does not see as man sees; for man looks at the outward appearance, but the LORD looks at the heart.', 'NKJV', 'Perspective'),
('0188b8e0-1234-7abc-8def-10000000122', '2 Samuel 22:31', 'As for God, His way is perfect; The word of the LORD is proven; He is a shield to all who trust in Him.', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-10000000123', '1 Kings 8:56', 'Blessed be the LORD, who has given rest to His people Israel, according to all that He promised. There has not failed one word of all His good promise.', 'NKJV', 'Faithfulness'),
('0188b8e0-1234-7abc-8def-10000000124', '2 Kings 6:16', 'So he answered, "Do not fear, for those who are with us are more than those who are with them."', 'NKJV', 'Courage'),
('0188b8e0-1234-7abc-8def-10000000125', '1 Chronicles 16:11', 'Seek the LORD and His strength; Seek His face evermore!', 'NKJV', 'Seeking God'),
('0188b8e0-1234-7abc-8def-10000000126', '2 Chronicles 20:15', 'Do not be afraid nor dismayed because of this great multitude, for the battle is not yours, but God’s.', 'NKJV', 'Trust'),
('0188b8e0-1234-7abc-8def-10000000127', 'Ezra 8:22', 'The hand of our God is upon all those for good who seek Him, but His power and His wrath are against all those who forsake Him.', 'NKJV', 'Guidance'),
('0188b8e0-1234-7abc-8def-10000000128', 'Nehemiah 8:10', 'Do not sorrow, for the joy of the LORD is your strength.', 'NKJV', 'Joy'),
('0188b8e0-1234-7abc-8def-10000000129', 'Esther 4:14', 'Yet who knows whether you have come to the kingdom for such a time as this?', 'NKJV', 'Purpose'),
('0188b8e0-1234-7abc-8def-10000000130', 'Job 19:25', 'For I know that my Redeemer lives, And He shall stand at last on the earth.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-10000000131', 'Psalm 16:11', 'You will show me the path of life; In Your presence is fullness of joy; At Your right hand are pleasures forevermore.', 'NKJV', 'Joy'),
('0188b8e0-1234-7abc-8def-10000000132', 'Proverbs 17:17', 'A friend loves at all times, And a brother is born for adversity.', 'NKJV', 'Friendship'),
('0188b8e0-1234-7abc-8def-10000000133', 'Ecclesiastes 3:1', 'To everything there is a season, A time for every purpose under heaven.', 'NKJV', 'Timing'),
('0188b8e0-1234-7abc-8def-10000000134', 'Song of Solomon 2:4', 'He brought me to the banqueting house, And his banner over me was love.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-10000000135', 'Isaiah 9:6', 'For unto us a Child is born, Unto us a Son is given; And the government will be upon His shoulder. And His name will be called Wonderful, Counselor, Mighty God...', 'NKJV', 'Prophecy'),
('0188b8e0-1234-7abc-8def-10000000136', 'Jeremiah 32:17', 'Ah, Lord GOD! Behold, You have made the heavens and the earth by Your great power and outstretched arm. There is nothing too hard for You.', 'NKJV', 'Power'),
('0188b8e0-1234-7abc-8def-10000000137', 'Ezekiel 36:26', 'I will give you a new heart and put a new spirit within you; I will take the heart of stone out of your flesh and give you a heart of flesh.', 'NKJV', 'Renewal'),
('0188b8e0-1234-7abc-8def-10000000138', 'Daniel 12:3', 'Those who are wise shall shine Like the brightness of the firmament, And those who turn many to righteousness Like the stars forever and ever.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-10000000139', 'Hosea 6:3', 'Let us know, Let us pursue the knowledge of the LORD. His going forth is established as the morning; He will come to us like the rain...', 'NKJV', 'Pursuit'),
('0188b8e0-1234-7abc-8def-10000000140', 'Joel 2:25', 'So I will restore to you the years that the swarming locust has eaten, The crawling locust, The consuming locust, And the chewing locust...', 'NKJV', 'Restoration'),
('0188b8e0-1234-7abc-8def-10000000141', 'Amos 5:24', 'But let justice run down like water, And righteousness like a mighty stream.', 'NKJV', 'Justice'),
('0188b8e0-1234-7abc-8def-10000000142', 'Obadiah 1:15', 'For the day of the LORD upon all the nations is near; As you have done, it shall be done to you; Your reprisal shall return upon your own head.', 'NKJV', 'Justice'),
('0188b8e0-1234-7abc-8def-10000000143', 'Jonah 2:2', 'And he said: "I cried out to the LORD because of my affliction, And He answered me. Out of the belly of Sheol I cried, And You heard my voice."', 'NKJV', 'Deliverance'),
('0188b8e0-1234-7abc-8def-10000000144', 'Micah 7:8', 'Do not rejoice over me, my enemy; When I fall, I will arise; When I sit in darkness, The LORD will be a light to me.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-10000000145', 'Nahum 1:7', 'The LORD is good, A stronghold in the day of trouble; And He knows those who trust in Him.', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-10000000146', 'Habakkuk 3:19', 'The LORD God is my strength; He will make my feet like deer’s feet, And He will make me walk on my high hills.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-10000000147', 'Zephaniah 3:17', 'The LORD your God in your midst, The Mighty One, will save; He will rejoice over you with gladness, He will quiet you with His love...', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-10000000148', 'Haggai 2:9', 'The glory of this latter temple shall be greater than the former, says the LORD of hosts. And in this place I will give peace...', 'NKJV', 'Promise'),
('0188b8e0-1234-7abc-8def-10000000149', 'Zechariah 4:6', 'So he answered and said to me: "This is the word of the LORD to Zerubbabel: Not by might nor by power, but by My Spirit, Says the LORD of hosts."', 'NKJV', 'Power'),
('0188b8e0-1234-7abc-8def-10000000150', 'Malachi 3:10', '"Bring all the tithes into the storehouse... And try Me now in this," Says the LORD of hosts, "If I will not open for you the windows of heaven..."', 'NKJV', 'Blessing'),
('0188b8e0-1234-7abc-8def-10000000151', 'Matthew 5:16', 'Let your light so shine before men, that they may see your good works and glorify your Father in heaven.', 'NKJV', 'Influence'),
('0188b8e0-1234-7abc-8def-10000000152', 'Mark 10:27', 'But Jesus looked at them and said, "With men it is impossible, but not with God; for with God all things are possible."', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-10000000153', 'Luke 1:37', 'For with God nothing will be impossible.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-10000000154', 'John 1:5', 'And the light shines in the darkness, and the darkness did not comprehend it.', 'NKJV', 'Light'),
('0188b8e0-1234-7abc-8def-10000000155', 'Acts 1:8', 'But you shall receive power when the Holy Spirit has come upon you; and you shall be witnesses to Me in Jerusalem, and in all Judea and Samaria...', 'NKJV', 'Power'),
('0188b8e0-1234-7abc-8def-10000000156', 'Romans 8:1', 'There is therefore now no condemnation to those who are in Christ Jesus, who do not walk according to the flesh, but according to the Spirit.', 'NKJV', 'Freedom'),
('0188b8e0-1234-7abc-8def-10000000157', '1 Corinthians 13:13', 'And now abide faith, hope, love, these three; but the greatest of these is love.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-10000000158', '2 Corinthians 5:7', 'For we walk by faith, not by sight.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-10000000159', 'Galatians 6:2', 'Bear one another’s burdens, and so fulfill the law of Christ.', 'NKJV', 'Community'),
('0188b8e0-1234-7abc-8def-10000000160', 'Ephesians 5:1', 'Therefore be imitators of God as dear children.', 'NKJV', 'Imitation'),
('0188b8e0-1234-7abc-8def-10000000161', 'Philippians 4:19', 'And my God shall supply all your need according to His riches in glory by Christ Jesus.', 'NKJV', 'Provision'),
('0188b8e0-1234-7abc-8def-10000000162', 'Colossians 1:16', 'For by Him all things were created that are in heaven and that are on earth... All things were created through Him and for Him.', 'NKJV', 'Creation'),
('0188b8e0-1234-7abc-8def-10000000163', '1 Thessalonians 5:11', 'Therefore comfort each other and edify one another, just as you also are doing.', 'NKJV', 'Encouragement'),
('0188b8e0-1234-7abc-8def-10000000164', '2 Thessalonians 3:3', 'But the Lord is faithful, who will establish you and guard you from the evil one.', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-10000000165', '1 Timothy 6:12', 'Fight the good fight of faith, lay hold on eternal life, to which you were also called and have confessed the good confession in the presence of many witnesses.', 'NKJV', 'Perseverance'),
('0188b8e0-1234-7abc-8def-10000000166', '2 Timothy 4:7', 'I have fought the good fight, I have finished the race, I have kept the faith.', 'NKJV', 'Endurance'),
('0188b8e0-1234-7abc-8def-10000000167', 'Titus 3:5', 'Not by works of righteousness which we have done, but according to His mercy He saved us, through the washing of regeneration and renewing of the Holy Spirit.', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-10000000168', 'Philemon 1:25', 'The grace of our Lord Jesus Christ be with your spirit. Amen.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-10000000169', 'Hebrews 12:14', 'Pursue peace with all people, and holiness, without which no one will see the Lord.', 'NKJV', 'Holiness'),
('0188b8e0-1234-7abc-8def-10000000170', 'James 4:7', 'Therefore submit to God. Resist the devil and he will flee from you.', 'NKJV', 'Submission'),
('0188b8e0-1234-7abc-8def-10000000171', '1 Peter 5:6', 'Therefore humble yourselves under the mighty hand of God, that He may exalt you in due time.', 'NKJV', 'Humility'),
('0188b8e0-1234-7abc-8def-10000000172', '2 Peter 1:3', 'As His divine power has given to us all things that pertain to life and godliness, through the knowledge of Him who called us by glory and virtue.', 'NKJV', 'Power'),
('0188b8e0-1234-7abc-8def-10000000173', '1 John 4:19', 'We love Him because He first loved us.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-10000000174', '2 John 1:6', 'This is love, that we walk according to His commandments. This is the commandment, that as you have heard from the beginning, you should walk in it.', 'NKJV', 'Obedience'),
('0188b8e0-1234-7abc-8def-10000000175', '3 John 1:4', 'I have no greater joy than to hear that my children walk in truth.', 'NKJV', 'Joy'),
('0188b8e0-1234-7abc-8def-10000000176', 'Jude 1:20', 'But you, beloved, building yourselves up on your most holy faith, praying in the Holy Spirit.', 'NKJV', 'Growth'),
('0188b8e0-1234-7abc-8def-10000000177', 'Revelation 22:13', 'I am the Alpha and the Omega, the Beginning and the End, the First and the Last.', 'NKJV', 'Eternity'),
('0188b8e0-1234-7abc-8def-10000000178', 'Psalm 27:14', 'Wait on the LORD; Be of good courage, And He shall strengthen your heart; Wait, I say, on the LORD!', 'NKJV', 'Patience'),
('0188b8e0-1234-7abc-8def-10000000179', 'Isaiah 26:4', 'Trust in the LORD forever, For in YAH, the LORD, is everlasting strength.', 'NKJV', 'Trust'),
('0188b8e0-1234-7abc-8def-10000000180', 'Matthew 6:34', 'Therefore do not worry about tomorrow, for tomorrow will worry about its own things. Sufficient for the day is its own trouble.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-10000000181', 'Romans 15:5', 'Now may the God of patience and comfort grant you to be like-minded toward one another, according to Christ Jesus.', 'NKJV', 'Unity'),
('0188b8e0-1234-7abc-8def-10000000182', 'Ephesians 4:15', 'But, speaking the truth in love, may grow up in all things into Him who is the head—Christ.', 'NKJV', 'Growth'),
('0188b8e0-1234-7abc-8def-10000000183', 'Colossians 4:2', 'Continue earnestly in prayer, being vigilant in it with thanksgiving.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-10000000184', '1 Thessalonians 5:24', 'He who calls you is faithful, who also will do it.', 'NKJV', 'Faithfulness'),
('0188b8e0-1234-7abc-8def-10000000185', 'Hebrews 10:24', 'And let us consider one another in order to stir up love and good works.', 'NKJV', 'Community'),
('0188b8e0-1234-7abc-8def-10000000186', 'James 1:17', 'Every good gift and every perfect gift is from above, and comes down from the Father of lights, with whom there is no variation or shadow of turning.', 'NKJV', 'Goodness'),
('0188b8e0-1234-7abc-8def-10000000187', '1 Peter 4:8', 'And above all things have fervent love for one another, for "love will cover a multitude of sins."', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-10000000188', '1 John 4:12', 'No one has seen God at any time. If we love one another, God abides in us, and His love has been perfected in us.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-10000000189', 'Revelation 3:11', 'Behold, I am coming quickly! Hold fast what you have, that no one may take your crown.', 'NKJV', 'Perseverance'),
('0188b8e0-1234-7abc-8def-10000000190', 'Psalm 103:1-2', 'Bless the LORD, O my soul; And all that is within me, bless His holy name! Bless the LORD, O my soul, And forget not all His benefits.', 'NKJV', 'Praise'),
('0188b8e0-1234-7abc-8def-10000000191', 'Proverbs 15:1', 'A soft answer turns away wrath, But a harsh word stirs up anger.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-10000000192', 'Isaiah 55:8-9', '"For My thoughts are not your thoughts, Nor are your ways My ways," says the LORD. "For as the heavens are higher than the earth, So are My ways higher than your ways..."', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-10000000193', 'Matthew 7:7', 'Ask, and it will be given to you; seek, and you will find; knock, and it will be opened to you.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-10000000194', 'Luke 6:31', 'And just as you want men to do to you, you also do to them likewise.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-10000000195', 'John 13:34', 'A new commandment I give to you, that you love one another; as I have loved you, that you also love one another.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-10000000196', 'Acts 20:35', 'I have shown you in every way, by laboring like this, that you must support the weak. And remember the words of the Lord Jesus, that He said, "It is more blessed to give than to receive."', 'NKJV', 'Generosity'),
('0188b8e0-1234-7abc-8def-10000000197', 'Romans 12:15', 'Rejoice with those who rejoice, and weep with those who weep.', 'NKJV', 'Empathy'),
('0188b8e0-1234-7abc-8def-10000000198', '1 Corinthians 10:31', 'Therefore, whether you eat or drink, or whatever you do, do all to the glory of God.', 'NKJV', 'Purpose'),
('0188b8e0-1234-7abc-8def-10000000199', '2 Corinthians 9:7', 'So let each one give as he purposes in his heart, not grudgingly or of necessity; for God loves a cheerful giver.', 'NKJV', 'Generosity'),
('0188b8e0-1234-7abc-8def-10000000200', 'Galatians 5:13', 'For you, brethren, have been called to liberty; only do not use liberty as an opportunity for the flesh, but through love serve one another.', 'NKJV', 'Service'),
('0188b8e0-1234-7abc-8def-10000000201', 'Ephesians 4:26', '"Be angry, and do not sin": do not let the sun go down on your wrath.', 'NKJV', 'Self-Control'),
('0188b8e0-1234-7abc-8def-10000000202', 'Philippians 2:14-15', 'Do all things without complaining and disputing, that you may become blameless and harmless, children of God without fault in the midst of a crooked and perverse generation...', 'NKJV', 'Attitude'),
('0188b8e0-1234-7abc-8def-10000000203', 'Colossians 3:17', 'And whatever you do in word or deed, do all in the name of the Lord Jesus, giving thanks to God the Father through Him.', 'NKJV', 'Purpose'),
('0188b8e0-1234-7abc-8def-10000000204', '1 Thessalonians 4:11', 'That you also aspire to lead a quiet life, to mind your own business, and to work with your own hands, as we commanded you.', 'NKJV', 'Diligence'),
('0188b8e0-1234-7abc-8def-10000000205', '2 Timothy 2:15', 'Be diligent to present yourself approved to God, a worker who does not need to be ashamed, rightly dividing the word of truth.', 'NKJV', 'Study'),
('0188b8e0-1234-7abc-8def-10000000206', 'Hebrews 11:1', 'Now faith is the substance of things hoped for, the evidence of things not seen.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-10000000207', 'James 1:19', 'So then, my beloved brethren, let every man be swift to hear, slow to speak, slow to wrath.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-10000000208', '1 Peter 3:10', 'For "He who would love life And see good days, Let him refrain his tongue from evil, And his lips from speaking deceit."', 'NKJV', 'Speech'),
('0188b8e0-1234-7abc-8def-10000000209', '1 John 1:7', 'But if we walk in the light as He is in the light, we have fellowship with one another, and the blood of Jesus Christ His Son cleanses us from all sin.', 'NKJV', 'Fellowship'),
('0188b8e0-1234-7abc-8def-10000000210', 'Revelation 21:5', 'Then He who sat on the throne said, "Behold, I make all things new." And He said to me, "Write, for these words are true and faithful."', 'NKJV', 'Renewal'),
('0188b8e0-1234-7abc-8def-10000000211', 'Psalm 119:11', 'Your word I have hidden in my heart, That I might not sin against You.', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-10000000212', 'Proverbs 3:3', 'Let not mercy and truth forsake you; Bind them around your neck, Write them on the tablet of your heart.', 'NKJV', 'Mercy'),
('0188b8e0-1234-7abc-8def-10000000213', 'Isaiah 40:8', 'The grass withers, the flower fades, But the word of our God stands forever.', 'NKJV', 'Eternity'),
('0188b8e0-1234-7abc-8def-10000000214', 'Matthew 18:20', 'For where two or three are gathered together in My name, I am there in the midst of them.', 'NKJV', 'Presence'),
('0188b8e0-1234-7abc-8def-10000000215', 'Luke 12:34', 'For where your treasure is, there your heart will be also.', 'NKJV', 'Values'),
('0188b8e0-1234-7abc-8def-10000000216', 'John 8:32', 'And you shall know the truth, and the truth shall make you free.', 'NKJV', 'Truth'),
('0188b8e0-1234-7abc-8def-10000000217', 'Acts 16:31', 'So they said, "Believe on the Lord Jesus Christ, and you will be saved, you and your household."', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-10000000218', 'Romans 14:8', 'For if we live, we live to the Lord; and if we die, we die to the Lord. Therefore, whether we live or die, we are the Lord’s.', 'NKJV', 'Commitment'),
('0188b8e0-1234-7abc-8def-10000000219', '1 Corinthians 16:13', 'Watch, stand fast in the faith, be brave, be strong.', 'NKJV', 'Courage'),
('0188b8e0-1234-7abc-8def-10000000220', '2 Corinthians 1:3-4', 'Blessed be the God and Father of our Lord Jesus Christ, the Father of mercies and God of all comfort, who comforts us in all our tribulation...', 'NKJV', 'Comfort'),
('0188b8e0-1234-7abc-8def-10000000221', 'Galatians 3:28', 'There is neither Jew nor Greek, there is neither slave nor free, there is neither male nor female; for you are all one in Christ Jesus.', 'NKJV', 'Equality'),
('0188b8e0-1234-7abc-8def-10000000222', 'Ephesians 2:4-5', 'But God, who is rich in mercy, because of His great love with which He loved us, even when we were dead in trespasses, made us alive together with Christ...', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-10000000223', 'Philippians 1:21', 'For to me, to live is Christ, and to die is gain.', 'NKJV', 'Purpose'),
('0188b8e0-1234-7abc-8def-10000000224', 'Colossians 2:6-7', 'As you therefore have received Christ Jesus the Lord, so walk in Him, rooted and built up in Him and established in the faith...', 'NKJV', 'Growth'),
('0188b8e0-1234-7abc-8def-10000000225', '1 Thessalonians 5:14', 'Now we exhort you, brethren, warn those who are unruly, comfort the fainthearted, uphold the weak, be patient with all.', 'NKJV', 'Patience'),
('0188b8e0-1234-7abc-8def-10000000226', '2 Timothy 1:9', 'Who has saved us and called us with a holy calling, not according to our works, but according to His own purpose and grace...', 'NKJV', 'Calling'),
('0188b8e0-1234-7abc-8def-10000000227', 'Hebrews 4:12', 'For the word of God is living and powerful, and sharper than any two-edged sword, piercing even to the division of soul and spirit...', 'NKJV', 'Word'),
('0188b8e0-1234-7abc-8def-10000000228', 'James 1:22', 'But be doers of the word, and not hearers only, deceiving yourselves.', 'NKJV', 'Action'),
('0188b8e0-1234-7abc-8def-10000000229', '1 Peter 2:2', 'As newborn babes, desire the pure milk of the word, that you may grow thereby.', 'NKJV', 'Growth'),
('0188b8e0-1234-7abc-8def-10000000230', '1 John 2:15', 'Do not love the world or the things in the world. If anyone loves the world, the love of the Father is not in him.', 'NKJV', 'Focus'),
('0188b8e0-1234-7abc-8def-10000000231', 'Psalm 119:9', 'How can a young man cleanse his way? By taking heed according to Your word.', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-10000000232', 'Proverbs 14:12', 'There is a way that seems right to a man, But its end is the way of death.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-10000000233', 'Isaiah 53:5', 'But He was wounded for our transgressions, He was bruised for our iniquities; The chastisement for our peace was upon Him, And by His stripes we are healed.', 'NKJV', 'Healing'),
('0188b8e0-1234-7abc-8def-10000000234', 'Matthew 22:37-39', 'Jesus said to him, "You shall love the LORD your God with all your heart, with all your soul, and with all your mind... And the second is like it: You shall love your neighbor as yourself."', 'NKJV', 'Commandment'),
('0188b8e0-1234-7abc-8def-10000000235', 'Luke 19:10', 'For the Son of Man has come to seek and to save that which was lost.', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-10000000236', 'John 10:10', 'The thief does not come except to steal, and to kill, and to destroy. I have come that they may have life, and that they may have it more abundantly.', 'NKJV', 'Life'),
('0188b8e0-1234-7abc-8def-10000000237', 'Acts 2:38', 'Then Peter said to them, "Repent, and let every one of you be baptized in the name of Jesus Christ for the remission of sins; and you shall receive the gift of the Holy Spirit."', 'NKJV', 'Repentance'),
('0188b8e0-1234-7abc-8def-10000000238', 'Romans 10:17', 'So then faith comes by hearing, and hearing by the word of God.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-10000000239', '1 Corinthians 2:9', 'But as it is written: "Eye has not seen, nor ear heard, Nor have entered into the heart of man The things which God has prepared for those who love Him."', 'NKJV', 'Promise'),
('0188b8e0-1234-7abc-8def-10000000240', '2 Corinthians 10:4', 'For the weapons of our warfare are not carnal but mighty in God for pulling down strongholds.', 'NKJV', 'Warfare'),
('0188b8e0-1234-7abc-8def-10000000241', 'Galatians 5:16', 'I say then: Walk in the Spirit, and you shall not fulfill the lust of the flesh.', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-10000000242', 'Ephesians 5:8', 'For you were once darkness, but now you are light in the Lord. Walk as children of light.', 'NKJV', 'Light'),
('0188b8e0-1234-7abc-8def-10000000243', 'Philippians 3:20', 'For our citizenship is in heaven, from which we also eagerly wait for the Savior, the Lord Jesus Christ.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-10000000244', 'Colossians 4:5', 'Walk in wisdom toward those who are outside, redeeming the time.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-10000000245', '1 Thessalonians 5:19', 'Do not quench the Spirit.', 'NKJV', 'Spirit'),
('0188b8e0-1234-7abc-8def-10000000246', '2 Timothy 2:22', 'Flee also youthful lusts; but pursue righteousness, faith, love, peace with those who call on the Lord out of a pure heart.', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-10000000247', 'Hebrews 12:28', 'Therefore, since we are receiving a kingdom which cannot be shaken, let us have grace, by which we may serve God acceptably with reverence and godly fear.', 'NKJV', 'Reverence'),
('0188b8e0-1234-7abc-8def-10000000248', 'James 1:12', 'Blessed is the man who endures temptation; for when he has been approved, he will receive the crown of life which the Lord has promised to those who love Him.', 'NKJV', 'Endurance'),
('0188b8e0-1234-7abc-8def-10000000249', '1 Peter 5:5', 'Likewise you younger people, submit yourselves to your elders. Yes, all of you be submissive to one another, and be clothed with humility...', 'NKJV', 'Humility'),
('0188b8e0-1234-7abc-8def-100000000250', '1 John 5:4', 'For whatever is born of God overcomes the world. And this is the victory that has overcome the world—our faith.', 'NKJV', 'Victory'),
('0188b8e0-1234-7abc-8def-100000000251', 'Psalm 4:8', 'I will both lie down in peace, and sleep; For You alone, O LORD, make me dwell in safety.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000252', 'Psalm 9:9', 'The LORD also will be a refuge for the oppressed, A refuge in times of trouble.', 'NKJV', 'Refuge'),
('0188b8e0-1234-7abc-8def-100000000253', 'Psalm 16:8', 'I have set the LORD always before me; Because He is at my right hand I shall not be moved.', 'NKJV', 'Stability'),
('0188b8e0-1234-7abc-8def-100000000254', 'Psalm 18:2', 'The LORD is my rock and my fortress and my deliverer; My God, my strength, in whom I will trust.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000255', 'Psalm 20:7', 'Some trust in chariots, and some in horses; But we will remember the name of the LORD our God.', 'NKJV', 'Trust'),
('0188b8e0-1234-7abc-8def-100000000256', 'Psalm 25:4-5', 'Show me Your ways, O LORD; Teach me Your paths. Lead me in Your truth and teach me, For You are the God of my salvation.', 'NKJV', 'Guidance'),
('0188b8e0-1234-7abc-8def-100000000257', 'Psalm 28:7', 'The LORD is my strength and my shield; My heart trusted in Him, and I am helped; Therefore my heart greatly rejoices.', 'NKJV', 'Joy'),
('0188b8e0-1234-7abc-8def-100000000258', 'Psalm 30:5', 'For His anger is but for a moment, His favor is for life; Weeping may endure for a night, But joy comes in the morning.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-100000000259', 'Psalm 31:24', 'Be of good courage, And He shall strengthen your heart, All you who hope in the LORD.', 'NKJV', 'Courage'),
('0188b8e0-1234-7abc-8def-100000000260', 'Psalm 32:7', 'You are my hiding place; You shall preserve me from trouble; You shall surround me with songs of deliverance.', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-100000000261', 'Psalm 33:20', 'Our soul waits for the LORD; He is our help and our shield.', 'NKJV', 'Patience'),
('0188b8e0-1234-7abc-8def-100000000262', 'Psalm 34:4', 'I sought the LORD, and He heard me, And delivered me from all my fears.', 'NKJV', 'Deliverance'),
('0188b8e0-1234-7abc-8def-100000000263', 'Psalm 34:8', 'Oh, taste and see that the LORD is good; Blessed is the man who trusts in Him!', 'NKJV', 'Goodness'),
('0188b8e0-1234-7abc-8def-100000000264', 'Psalm 37:4', 'Delight yourself also in the LORD, And He shall give you the desires of your heart.', 'NKJV', 'Desire'),
('0188b8e0-1234-7abc-8def-100000000265', 'Psalm 37:5', 'Commit your way to the LORD, Trust also in Him, And He shall bring it to pass.', 'NKJV', 'Commitment'),
('0188b8e0-1234-7abc-8def-100000000266', 'Psalm 37:23-24', 'The steps of a good man are ordered by the LORD, And He delights in his way. Though he fall, he shall not be utterly cast down.', 'NKJV', 'Guidance'),
('0188b8e0-1234-7abc-8def-100000000267', 'Psalm 40:1-2', 'I waited patiently for the LORD; And He inclined to me, And heard my cry. He also brought me up out of a horrible pit.', 'NKJV', 'Deliverance'),
('0188b8e0-1234-7abc-8def-100000000268', 'Psalm 46:5', 'God is in the midst of her, she shall not be moved; God shall help her, just at the break of dawn.', 'NKJV', 'Stability'),
('0188b8e0-1234-7abc-8def-100000000269', 'Psalm 55:22', 'Cast your burden on the LORD, And He shall sustain you; He shall never permit the righteous to be moved.', 'NKJV', 'Comfort'),
('0188b8e0-1234-7abc-8def-100000000270', 'Psalm 56:3', 'Whenever I am afraid, I will trust in You.', 'NKJV', 'Trust'),
('0188b8e0-1234-7abc-8def-100000000271', 'Psalm 61:2', 'From the end of the earth I will cry to You, When my heart is overwhelmed; Lead me to the rock that is higher than I.', 'NKJV', 'Refuge'),
('0188b8e0-1234-7abc-8def-100000000272', 'Psalm 62:1-2', 'Truly my soul silently waits for God; From Him comes my salvation. He only is my rock and my salvation.', 'NKJV', 'Patience'),
('0188b8e0-1234-7abc-8def-100000000273', 'Psalm 73:26', 'My flesh and my heart fail; But God is the strength of my heart and my portion forever.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000274', 'Psalm 84:11', 'For the LORD God is a sun and shield; The LORD will give grace and glory; No good thing will He withhold From those who walk uprightly.', 'NKJV', 'Blessing'),
('0188b8e0-1234-7abc-8def-100000000275', 'Psalm 90:12', 'So teach us to number our days, That we may gain a heart of wisdom.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-100000000276', 'Psalm 94:19', 'In the multitude of my anxieties within me, Your comforts delight my soul.', 'NKJV', 'Comfort'),
('0188b8e0-1234-7abc-8def-100000000277', 'Psalm 100:4', 'Enter into His gates with thanksgiving, And into His courts with praise. Be thankful to Him, and bless His name.', 'NKJV', 'Praise'),
('0188b8e0-1234-7abc-8def-100000000278', 'Psalm 105:4', 'Seek the LORD and His strength; Seek His face evermore!', 'NKJV', 'Seeking'),
('0188b8e0-1234-7abc-8def-100000000279', 'Psalm 107:1', 'Oh, give thanks to the LORD, for He is good! For His mercy endures forever.', 'NKJV', 'Mercy'),
('0188b8e0-1234-7abc-8def-100000000280', 'Psalm 118:6', 'The LORD is on my side; I will not fear. What can man do to me?', 'NKJV', 'Courage'),
('0188b8e0-1234-7abc-8def-100000000281', 'Psalm 118:14', 'The LORD is my strength and song, And He has become my salvation.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000282', 'Psalm 119:105', 'Your word is a lamp to my feet And a light to my path.', 'NKJV', 'Guidance'),
('0188b8e0-1234-7abc-8def-100000000283', 'Psalm 119:114', 'You are my hiding place and my shield; I hope in Your word.', 'NKJV', 'Protection'),
('0188b8e0-1234-7abc-8def-100000000284', 'Psalm 127:1', 'Unless the LORD builds the house, They labor in vain who build it; Unless the LORD guards the city, The watchman stays awake in vain.', 'NKJV', 'Dependence'),
('0188b8e0-1234-7abc-8def-100000000285', 'Psalm 130:5', 'I wait for the LORD, my soul waits, And in His word I do hope.', 'NKJV', 'Patience'),
('0188b8e0-1234-7abc-8def-100000000286', 'Psalm 138:8', 'The LORD will perfect that which concerns me; Your mercy, O LORD, endures forever; Do not forsake the works of Your hands.', 'NKJV', 'Promise'),
('0188b8e0-1234-7abc-8def-100000000287', 'Psalm 143:8', 'Cause me to hear Your lovingkindness in the morning, For in You do I trust; Cause me to know the way in which I should walk.', 'NKJV', 'Guidance'),
('0188b8e0-1234-7abc-8def-100000000288', 'Psalm 145:18', 'The LORD is near to all who call upon Him, To all who call upon Him in truth.', 'NKJV', 'Presence'),
('0188b8e0-1234-7abc-8def-100000000289', 'Psalm 147:3', 'He heals the brokenhearted And binds up their wounds.', 'NKJV', 'Healing'),
('0188b8e0-1234-7abc-8def-100000000290', 'Proverbs 1:7', 'The fear of the LORD is the beginning of knowledge, But fools despise wisdom and instruction.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-100000000291', 'Proverbs 3:9-10', 'Honor the LORD with your possessions, And with the firstfruits of all your increase; So your barns will be filled with plenty.', 'NKJV', 'Generosity'),
('0188b8e0-1234-7abc-8def-100000000292', 'Proverbs 11:25', 'The generous soul will be made rich, And he who waters will also be watered himself.', 'NKJV', 'Generosity'),
('0188b8e0-1234-7abc-8def-100000000293', 'Proverbs 12:25', 'Anxiety in the heart of man causes depression, But a good word makes it glad.', 'NKJV', 'Encouragement'),
('0188b8e0-1234-7abc-8def-100000000294', 'Proverbs 16:9', 'A man’s heart plans his way, But the LORD directs his steps.', 'NKJV', 'Guidance'),
('0188b8e0-1234-7abc-8def-100000000295', 'Proverbs 18:24', 'A man who has friends must himself be friendly, But there is a friend who sticks closer than a brother.', 'NKJV', 'Friendship'),
('0188b8e0-1234-7abc-8def-100000000296', 'Proverbs 21:21', 'He who follows righteousness and mercy Finds life, righteousness, and honor.', 'NKJV', 'Righteousness'),
('0188b8e0-1234-7abc-8def-100000000297', 'Proverbs 22:6', 'Train up a child in the way he should go, And when he is old he will not depart from it.', 'NKJV', 'Family'),
('0188b8e0-1234-7abc-8def-100000000298', 'Proverbs 27:17', 'As iron sharpens iron, So a man sharpens the countenance of his friend.', 'NKJV', 'Community'),
('0188b8e0-1234-7abc-8def-100000000299', 'Ecclesiastes 4:9-10', 'Two are better than one, Because they have a good reward for their labor. For if they fall, one will lift up his companion.', 'NKJV', 'Community'),
('0188b8e0-1234-7abc-8def-100000000300', 'Isaiah 1:18', '"Come now, and let us reason together," Says the LORD, "Though your sins are like scarlet, They shall be as white as snow."', 'NKJV', 'Forgiveness'),
('0188b8e0-1234-7abc-8def-100000000301', 'Isaiah 12:2', 'Behold, God is my salvation, I will trust and not be afraid; For YAH, the LORD, is my strength and song.', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000302', 'Isaiah 26:3', 'You will keep him in perfect peace, Whose mind is stayed on You, Because he trusts in You.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000303', 'Isaiah 30:18', 'Therefore the LORD will wait, that He may be gracious to you; And therefore He will be exalted, that He may have mercy on you.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-100000000304', 'Isaiah 40:29', 'He gives power to the weak, And to those who have no might He increases strength.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000305', 'Isaiah 43:1', 'But now, thus says the LORD, who created you, O Jacob... "Fear not, for I have redeemed you; I have called you by your name; You are Mine."', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000306', 'Isaiah 43:18-19', '"Do not remember the former things, Nor consider the things of old. Behold, I will do a new thing, Now it shall spring forth..."', 'NKJV', 'Renewal'),
('0188b8e0-1234-7abc-8def-100000000307', 'Isaiah 46:4', 'Even to your old age, I am He, And even to gray hairs I will carry you! I have made, and I will bear; Even I will carry, and will deliver you.', 'NKJV', 'Faithfulness'),
('0188b8e0-1234-7abc-8def-100000000308', 'Isaiah 54:10', '"For the mountains shall depart And the hills be removed, But My kindness shall not depart from you, Nor shall My covenant of peace be removed..."', 'NKJV', 'Covenant'),
('0188b8e0-1234-7abc-8def-100000000309', 'Isaiah 55:6', 'Seek the LORD while He may be found, Call upon Him while He is near.', 'NKJV', 'Seeking'),
('0188b8e0-1234-7abc-8def-100000000310', 'Isaiah 58:11', 'The LORD will guide you continually, And satisfy your soul in drought, And strengthen your bones; You shall be like a watered garden...', 'NKJV', 'Guidance'),
('0188b8e0-1234-7abc-8def-100000000311', 'Isaiah 60:1', 'Arise, shine; For your light has come! And the glory of the LORD is risen upon you.', 'NKJV', 'Glory'),
('0188b8e0-1234-7abc-8def-100000000312', 'Isaiah 61:3', 'To console those who mourn in Zion, To give them beauty for ashes, The oil of joy for mourning, The garment of praise for the spirit of heaviness.', 'NKJV', 'Restoration'),
('0188b8e0-1234-7abc-8def-100000000313', 'Jeremiah 17:7-8', 'Blessed is the man who trusts in the LORD, And whose hope is the LORD. For he shall be like a tree planted by the waters...', 'NKJV', 'Trust'),
('0188b8e0-1234-7abc-8def-100000000314', 'Jeremiah 29:12-13', 'Then you will call upon Me and go and pray to Me, and I will listen to you. And you will seek Me and find Me, when you search for Me with all your heart.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000315', 'Lamentations 3:25-26', 'The LORD is good to those who wait for Him, To the soul who seeks Him. It is good that one should hope and wait quietly For the salvation of the LORD.', 'NKJV', 'Patience'),
('0188b8e0-1234-7abc-8def-100000000316', 'Ezekiel 11:19', 'Then I will give them one heart, and I will put a new spirit within them, and take the stony heart out of their flesh, and give them a heart of flesh.', 'NKJV', 'Renewal'),
('0188b8e0-1234-7abc-8def-100000000317', 'Daniel 3:17-18', 'If that is the case, our God whom we serve is able to deliver us from the burning fiery furnace... But if not, let it be known to you, O king, that we do not serve your gods.', 'NKJV', 'Courage'),
('0188b8e0-1234-7abc-8def-100000000318', 'Hosea 10:12', 'Sow for yourselves righteousness; Reap in mercy; Break up your fallow ground, For it is time to seek the LORD, Till He comes and rains righteousness on you.', 'NKJV', 'Righteousness'),
('0188b8e0-1234-7abc-8def-100000000319', 'Joel 2:28', 'And it shall come to pass afterward That I will pour out My Spirit on all flesh; Your sons and your daughters shall prophesy...', 'NKJV', 'Prophecy'),
('0188b8e0-1234-7abc-8def-100000000320', 'Amos 4:13', 'For behold, He who forms mountains, And creates the wind, Who declares to man what his thought is... The LORD God of hosts is His name.', 'NKJV', 'Power'),
('0188b8e0-1234-7abc-8def-100000000321', 'Jonah 2:7', 'When my soul fainted within me, I remembered the LORD; And my prayer went up to You, Into Your holy temple.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000322', 'Micah 6:8', 'He has shown you, O man, what is good; And what does the LORD require of you But to do justly, To love mercy, And to walk humbly with your God?', 'NKJV', 'Humility'),
('0188b8e0-1234-7abc-8def-100000000323', 'Habakkuk 2:3', 'For the vision is yet for an appointed time; But at the end it will speak, and it will not lie. Though it tarries, wait for it; Because it will surely come.', 'NKJV', 'Timing'),
('0188b8e0-1234-7abc-8def-100000000324', 'Zechariah 9:12', 'Return to the stronghold, You prisoners of hope. Even today I declare That I will restore double to you.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-100000000325', 'Malachi 4:2', 'But to you who fear My name The Sun of Righteousness shall arise With healing in His wings; And you shall go out And grow fat like stall-fed calves.', 'NKJV', 'Healing'),
('0188b8e0-1234-7abc-8def-100000000326', 'Matthew 4:4', 'But He answered and said, "It is written, ‘Man shall not live by bread alone, but by every word that proceeds from the mouth of God.’"', 'NKJV', 'Word'),
('0188b8e0-1234-7abc-8def-100000000327', 'Matthew 5:6', 'Blessed are those who hunger and thirst for righteousness, For they shall be filled.', 'NKJV', 'Righteousness'),
('0188b8e0-1234-7abc-8def-100000000328', 'Matthew 5:8', 'Blessed are the pure in heart, For they shall see God.', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-100000000329', 'Matthew 5:9', 'Blessed are the peacemakers, For they shall be called sons of God.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000330', 'Matthew 6:6', 'But you, when you pray, go into your room, and when you have shut your door, pray to your Father who is in the secret place...', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000331', 'Matthew 6:19-20', 'Do not lay up for yourselves treasures on earth, where moth and rust destroy and where thieves break in and steal; but lay up for yourselves treasures in heaven...', 'NKJV', 'Values'),
('0188b8e0-1234-7abc-8def-100000000332', 'Matthew 6:21', 'For where your treasure is, there your heart will be also.', 'NKJV', 'Values'),
('0188b8e0-1234-7abc-8def-100000000333', 'Matthew 6:25-26', 'Therefore I say to you, do not worry about your life, what you will eat or what you will drink... Look at the birds of the air, for they neither sow nor reap...', 'NKJV', 'Trust'),
('0188b8e0-1234-7abc-8def-100000000334', 'Matthew 7:1-2', 'Judge not, that you be not judged. For with what judgment you judge, you will be judged; and with the measure you use, it will be measured back to you.', 'NKJV', 'Judgment'),
('0188b8e0-1234-7abc-8def-100000000335', 'Matthew 7:12', 'Therefore, whatever you want men to do to you, do also to them, for this is the Law and the Prophets.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000336', 'Matthew 10:29-31', 'Are not two sparrows sold for a copper coin? And not one of them falls to the ground apart from your Father... Do not fear therefore; you are of more value than many sparrows.', 'NKJV', 'Value'),
('0188b8e0-1234-7abc-8def-100000000337', 'Matthew 11:28-30', 'Come to Me, all you who labor and are heavy laden, and I will give you rest. Take My yoke upon you and learn from Me...', 'NKJV', 'Rest'),
('0188b8e0-1234-7abc-8def-100000000338', 'Matthew 18:3-4', 'Assuredly, I say to you, unless you are converted and become as little children, you will by no means enter the kingdom of heaven.', 'NKJV', 'Humility'),
('0188b8e0-1234-7abc-8def-100000000339', 'Matthew 19:14', 'But Jesus said, "Let the little children come to Me, and do not forbid them; for of such is the kingdom of heaven."', 'NKJV', 'Kingdom'),
('0188b8e0-1234-7abc-8def-100000000340', 'Matthew 24:35', 'Heaven and earth will pass away, but My words will by no means pass away.', 'NKJV', 'Eternity'),
('0188b8e0-1234-7abc-8def-100000000341', 'Mark 8:36', 'For what will it profit a man if he gains the whole world, and loses his own soul?', 'NKJV', 'Values'),
('0188b8e0-1234-7abc-8def-100000000342', 'Mark 9:23', 'Jesus said to him, "If you can believe, all things are possible to him who believes."', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000343', 'Mark 10:45', 'For even the Son of Man did not come to be served, but to serve, and to give His life a ransom for many.', 'NKJV', 'Service'),
('0188b8e0-1234-7abc-8def-100000000344', 'Mark 11:24', 'Therefore I say to you, whatever things you ask when you pray, believe that you receive them, and you will have them.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000345', 'Mark 12:30-31', 'And you shall love the LORD your God with all your heart, with all your soul... The second is this: You shall love your neighbor as yourself.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000346', 'Mark 16:15', 'And He said to them, "Go into all the world and preach the gospel to every creature."', 'NKJV', 'Mission'),
('0188b8e0-1234-7abc-8def-100000000347', 'Luke 6:27-28', 'But I say to you who hear: Love your enemies, do good to those who hate you, bless those who curse you, and pray for those who spitefully use you.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000348', 'Luke 6:35', 'But love your enemies, do good, and lend, hoping for nothing in return; and your reward will be great, and you will be sons of the Highest...', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000349', 'Luke 6:36', 'Therefore be merciful, just as your Father also is merciful.', 'NKJV', 'Mercy'),
('0188b8e0-1234-7abc-8def-100000000350', 'Luke 6:38', 'Give, and it will be given to you: good measure, pressed down, shaken together, and running over will be put into your bosom.', 'NKJV', 'Generosity'),
('0188b8e0-1234-7abc-8def-100000000351', 'Luke 9:23', 'Then He said to them all, "If anyone desires to come after Me, let him deny himself, and take up his cross daily, and follow Me."', 'NKJV', 'Discipleship'),
('0188b8e0-1234-7abc-8def-100000000352', 'Luke 11:9', 'So I say to you, ask, and it will be given to you; seek, and you will find; knock, and it will be opened to you.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000353', 'Luke 12:7', 'But the very hairs of your head are all numbered. Do not fear therefore; you are of more value than many sparrows.', 'NKJV', 'Value'),
('0188b8e0-1234-7abc-8def-100000000354', 'Luke 12:15', 'And He said to them, "Take heed and beware of covetousness, for one’s life does not consist in the abundance of the things he possesses."', 'NKJV', 'Values'),
('0188b8e0-1234-7abc-8def-100000000355', 'Luke 15:7', 'I say to you that likewise there will be more joy in heaven over one sinner who repents than over ninety-nine just persons who need no repentance.', 'NKJV', 'Joy'),
('0188b8e0-1234-7abc-8def-100000000356', 'Luke 16:10', 'He who is faithful in what is least is faithful also in much; and he who is unjust in what is least is unjust also in much.', 'NKJV', 'Faithfulness'),
('0188b8e0-1234-7abc-8def-100000000357', 'Luke 18:27', 'But He said, "The things which are impossible with men are possible with God."', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000358', 'Luke 21:33', 'Heaven and earth will pass away, but My words will by no means pass away.', 'NKJV', 'Eternity'),
('0188b8e0-1234-7abc-8def-100000000359', 'John 1:12', 'But as many as received Him, to them He gave the right to become children of God, to those who believe in His name.', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000360', 'John 1:14', 'And the Word became flesh and dwelt among us, and we beheld His glory, the glory as of the only begotten of the Father, full of grace and truth.', 'NKJV', 'Incarnation'),
('0188b8e0-1234-7abc-8def-100000000361', 'John 3:17', 'For God did not send His Son into the world to condemn the world, but that the world through Him might be saved.', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000362', 'John 4:24', 'God is Spirit, and those who worship Him must worship in spirit and truth.', 'NKJV', 'Worship'),
('0188b8e0-1234-7abc-8def-100000000363', 'John 5:24', 'Most assuredly, I say to you, he who hears My word and believes in Him who sent Me has everlasting life, and shall not come into judgment...', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000364', 'John 6:35', 'And Jesus said to them, "I am the bread of life. He who comes to Me shall never hunger, and he who believes in Me shall never thirst."', 'NKJV', 'Provision'),
('0188b8e0-1234-7abc-8def-100000000365', 'John 8:12', 'Then Jesus spoke to them again, saying, "I am the light of the world. He who follows Me shall not walk in darkness, but have the light of life."', 'NKJV', 'Light'),
('0188b8e0-1234-7abc-8def-100000000366', 'John 8:36', 'Therefore if the Son makes you free, you shall be free indeed.', 'NKJV', 'Freedom'),
('0188b8e0-1234-7abc-8def-100000000367', 'John 10:11', 'I am the good shepherd. The good shepherd gives His life for the sheep.', 'NKJV', 'Sacrifice'),
('0188b8e0-1234-7abc-8def-100000000368', 'John 10:27-28', 'My sheep hear My voice, and I know them, and they follow Me. And I give them eternal life, and they shall never perish...', 'NKJV', 'Assurance'),
('0188b8e0-1234-7abc-8def-100000000369', 'John 11:25-26', 'Jesus said to her, "I am the resurrection and the life. He who believes in Me, though he may die, he shall live..."', 'NKJV', 'Resurrection'),
('0188b8e0-1234-7abc-8def-100000000370', 'John 12:25', 'He who loves his life will lose it, and he who hates his life in this world will keep it for eternal life.', 'NKJV', 'Sacrifice'),
('0188b8e0-1234-7abc-8def-100000000371', 'John 13:7', 'Jesus answered and said to him, "What I am doing you do not understand now, but you will know after this."', 'NKJV', 'Trust'),
('0188b8e0-1234-7abc-8def-100000000372', 'John 13:35', 'By this all will know that you are My disciples, if you have love for one another.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000373', 'John 14:1', 'Let not your heart be troubled; you believe in God, believe also in Me.', 'NKJV', 'Comfort'),
('0188b8e0-1234-7abc-8def-100000000374', 'John 14:15', 'If you love Me, keep My commandments.', 'NKJV', 'Obedience'),
('0188b8e0-1234-7abc-8def-100000000375', 'John 14:21', 'He who has My commandments and keeps them, it is he who loves Me. And he who loves Me will be loved by My Father...', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000376', 'John 15:4', 'Abide in Me, and I in you. As the branch cannot bear fruit of itself, unless it abides in the vine, neither can you, unless you abide in Me.', 'NKJV', 'Connection'),
('0188b8e0-1234-7abc-8def-100000000377', 'John 15:7', 'If you abide in Me, and My words abide in you, you will ask what you desire, and it shall be done for you.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000378', 'John 15:11', 'These things I have spoken to you, that My joy may remain in you, and that your joy may be full.', 'NKJV', 'Joy'),
('0188b8e0-1234-7abc-8def-100000000379', 'John 15:12-13', 'This is My commandment, that you love one another as I have loved you. Greater love has no one than this, than to lay down one’s life for his friends.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000380', 'John 15:16', 'You did not choose Me, but I chose you and appointed you that you should go and bear fruit, and that your fruit should remain...', 'NKJV', 'Purpose'),
('0188b8e0-1234-7abc-8def-100000000381', 'John 16:24', 'Until now you have asked nothing in My name. Ask, and you will receive, that your joy may be full.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000382', 'John 17:3', 'And this is eternal life, that they may know You, the only true God, and Jesus Christ whom You have sent.', 'NKJV', 'Eternity'),
('0188b8e0-1234-7abc-8def-100000000383', 'John 17:17', 'Sanctify them by Your truth. Your word is truth.', 'NKJV', 'Truth'),
('0188b8e0-1234-7abc-8def-100000000384', 'John 20:29', 'Jesus said to him, "Thomas, because you have seen Me, you have believed. Blessed are those who have not seen and yet have believed."', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000385', 'Acts 2:21', 'And it shall come to pass That whoever calls on the name of the LORD Shall be saved.', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000386', 'Acts 3:19', 'Repent therefore and be converted, that your sins may be blotted out, so that times of refreshing may come from the presence of the Lord.', 'NKJV', 'Repentance'),
('0188b8e0-1234-7abc-8def-100000000387', 'Acts 4:20', 'For we cannot but speak the things which we have seen and heard.', 'NKJV', 'Testimony'),
('0188b8e0-1234-7abc-8def-100000000388', 'Acts 5:29', 'But Peter and the other apostles answered and said: "We ought to obey God rather than men."', 'NKJV', 'Obedience'),
('0188b8e0-1234-7abc-8def-100000000389', 'Acts 10:34-35', 'Then Peter opened his mouth and said: "In truth I perceive that God shows no partiality. But in every nation whoever fears Him and works righteousness is accepted by Him."', 'NKJV', 'Equality'),
('0188b8e0-1234-7abc-8def-100000000390', 'Acts 17:28', 'For in Him we live and move and have our being, as also some of your own poets have said, "For we are also His offspring."', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000391', 'Romans 1:17', 'For in it the righteousness of God is revealed from faith to faith; as it is written, "The just shall live by faith."', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000392', 'Romans 2:4', 'Or do you despise the riches of His goodness, forbearance, and longsuffering, not knowing that the goodness of God leads you to repentance?', 'NKJV', 'Repentance'),
('0188b8e0-1234-7abc-8def-100000000393', 'Romans 3:23-24', 'For all have sinned and fall short of the glory of God, being justified freely by His grace through the redemption that is in Christ Jesus.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-100000000394', 'Romans 4:20-21', 'He did not waver at the promise of God through unbelief, but was strengthened in faith, giving glory to God, and being fully convinced that what He had promised He was also able to perform.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000395', 'Romans 5:1', 'Therefore, having been justified by faith, we have peace with God through our Lord Jesus Christ.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000396', 'Romans 5:3-4', 'And not only that, but we also glory in tribulations, knowing that tribulation produces perseverance; and perseverance, character; and character, hope.', 'NKJV', 'Character'),
('0188b8e0-1234-7abc-8def-100000000397', 'Romans 5:5', 'Now hope does not disappoint, because the love of God has been poured out in our hearts by the Holy Spirit who was given to us.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-100000000398', 'Romans 6:14', 'For sin shall not have dominion over you, for you are not under law but under grace.', 'NKJV', 'Freedom'),
('0188b8e0-1234-7abc-8def-100000000399', 'Romans 8:6', 'For to be carnally minded is death, but to be spiritually minded is life and peace.', 'NKJV', 'Spirit'),
('0188b8e0-1234-7abc-8def-100000000400', 'Romans 8:14', 'For as many as are led by the Spirit of God, these are sons of God.', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000401', 'Romans 8:15', 'For you did not receive the spirit of bondage again to fear, but you received the Spirit of adoption by whom we cry out, "Abba, Father."', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000402', 'Romans 8:18', 'For I consider that the sufferings of this present time are not worthy to be compared with the glory which shall be revealed in us.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-100000000403', 'Romans 8:26', 'Likewise the Spirit also helps in our weaknesses. For we do not know what we should pray for as we ought, but the Spirit Himself makes intercession for us...', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000404', 'Romans 8:32', 'He who did not spare His own Son, but delivered Him up for us all, how shall He not with Him also freely give us all things?', 'NKJV', 'Provision'),
('0188b8e0-1234-7abc-8def-100000000405', 'Romans 8:37', 'Yet in all these things we are more than conquerors through Him who loved us.', 'NKJV', 'Victory'),
('0188b8e0-1234-7abc-8def-100000000406', 'Romans 10:10', 'For with the heart one believes unto righteousness, and with the mouth confession is made unto salvation.', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000407', 'Romans 10:13', 'For "whoever calls on the name of the LORD shall be saved."', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000408', 'Romans 11:33', 'Oh, the depth of the riches both of the wisdom and knowledge of God! How unsearchable are His judgments and His ways past finding out!', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-100000000409', 'Romans 12:3', 'For I say, through the grace given to me, to everyone who is among you, not to think of himself more highly than he ought to think...', 'NKJV', 'Humility'),
('0188b8e0-1234-7abc-8def-100000000410', 'Romans 12:9', 'Let love be without hypocrisy. Abhor what is evil. Cling to what is good.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000411', 'Romans 12:10', 'Be kindly affectionate to one another with brotherly love, in honor giving preference to one another.', 'NKJV', 'Community'),
('0188b8e0-1234-7abc-8def-100000000412', 'Romans 12:11', 'Not lagging in diligence, fervent in spirit, serving the Lord.', 'NKJV', 'Service'),
('0188b8e0-1234-7abc-8def-100000000413', 'Romans 12:14', 'Bless those who persecute you; bless and do not curse.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-100000000414', 'Romans 12:16', 'Be of the same mind toward one another. Do not set your mind on high things, but associate with the humble. Do not be wise in your own opinion.', 'NKJV', 'Humility'),
('0188b8e0-1234-7abc-8def-100000000415', 'Romans 12:18', 'If it is possible, as much as depends on you, live peaceably with all men.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000416', 'Romans 12:21', 'Do not be overcome by evil, but overcome evil with good.', 'NKJV', 'Goodness'),
('0188b8e0-1234-7abc-8def-100000000417', 'Romans 13:8', 'Owe no one anything except to love one another, for he who loves another has fulfilled the law.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000418', 'Romans 13:10', 'Love does no harm to a neighbor; therefore love is the fulfillment of the law.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000419', 'Romans 14:11', 'For it is written: "As I live, says the LORD, Every knee shall bow to Me, And every tongue shall confess to God."', 'NKJV', 'Worship'),
('0188b8e0-1234-7abc-8def-100000000420', 'Romans 14:17', 'For the kingdom of God is not eating and drinking, but righteousness and peace and joy in the Holy Spirit.', 'NKJV', 'Kingdom'),
('0188b8e0-1234-7abc-8def-100000000421', 'Romans 14:19', 'Therefore let us pursue the things which make for peace and the things by which one may edify another.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000422', 'Romans 15:4', 'For whatever things were written before were written for our learning, that we through the patience and comfort of the Scriptures might have hope.', 'NKJV', 'Scripture'),
('0188b8e0-1234-7abc-8def-100000000423', 'Romans 15:7', 'Therefore receive one another, just as Christ also received us, to the glory of God.', 'NKJV', 'Acceptance'),
('0188b8e0-1234-7abc-8def-100000000424', '1 Corinthians 1:9', 'God is faithful, by whom you were called into the fellowship of His Son, Jesus Christ our Lord.', 'NKJV', 'Faithfulness'),
('0188b8e0-1234-7abc-8def-100000000425', '1 Corinthians 1:18', 'For the message of the cross is foolishness to those who are perishing, but to us who are being saved it is the power of God.', 'NKJV', 'Power'),
('0188b8e0-1234-7abc-8def-100000000426', '1 Corinthians 1:25', 'Because the foolishness of God is wiser than men, and the weakness of God is stronger than men.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-100000000427', '1 Corinthians 1:27', 'But God has chosen the foolish things of the world to put to shame the wise, and God has chosen the weak things of the world to put to shame the things which are mighty.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-100000000428', '1 Corinthians 2:5', 'That your faith should not be in the wisdom of men but in the power of God.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000429', '1 Corinthians 2:12', 'Now we have received, not the spirit of the world, but the Spirit who is from God, that we might know the things that have been freely given to us by God.', 'NKJV', 'Spirit'),
('0188b8e0-1234-7abc-8def-100000000430', '1 Corinthians 3:11', 'For no other foundation can anyone lay than that which is laid, which is Jesus Christ.', 'NKJV', 'Foundation'),
('0188b8e0-1234-7abc-8def-100000000431', '1 Corinthians 3:16', 'Do you not know that you are the temple of God and that the Spirit of God dwells in you?', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000432', '1 Corinthians 6:19-20', 'Or do you not know that your body is the temple of the Holy Spirit who is in you, whom you have from God, and you are not your own? For you were bought at a price...', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-100000000433', '1 Corinthians 8:3', 'But if anyone loves God, this one is known by Him.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000434', '1 Corinthians 9:24', 'Do you not know that those who run in a race all run, but one receives the prize? Run in such a way that you may obtain it.', 'NKJV', 'Perseverance'),
('0188b8e0-1234-7abc-8def-100000000435', '1 Corinthians 10:12', 'Therefore let him who thinks he stands take heed lest he fall.', 'NKJV', 'Humility'),
('0188b8e0-1234-7abc-8def-100000000436', '1 Corinthians 11:1', 'Imitate me, just as I also imitate Christ.', 'NKJV', 'Example'),
('0188b8e0-1234-7abc-8def-100000000437', '1 Corinthians 12:27', 'Now you are the body of Christ, and members individually.', 'NKJV', 'Community'),
('0188b8e0-1234-7abc-8def-100000000438', '1 Corinthians 13:1-2', 'Though I speak with the tongues of men and of angels, but have not love, I have become sounding brass or a clanging cymbal...', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000439', '1 Corinthians 13:7', 'Love bears all things, believes all things, hopes all things, endures all things.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000440', '1 Corinthians 13:8', 'Love never fails. But whether there are prophecies, they will fail; whether there are tongues, they will cease; whether there is knowledge, it will vanish away.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000441', '1 Corinthians 14:33', 'For God is not the author of confusion but of peace, as in all the churches of the saints.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000442', '1 Corinthians 14:40', 'Let all things be done decently and in order.', 'NKJV', 'Order'),
('0188b8e0-1234-7abc-8def-100000000443', '1 Corinthians 15:10', 'But by the grace of God I am what I am, and His grace toward me was not in vain; but I labored more abundantly than they all, yet not I, but the grace of God which was with me.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-100000000444', '1 Corinthians 15:33', 'Do not be deceived: "Evil company corrupts good habits."', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-100000000445', '1 Corinthians 15:57', 'But thanks be to God, who gives us the victory through our Lord Jesus Christ.', 'NKJV', 'Victory'),
('0188b8e0-1234-7abc-8def-100000000446', '2 Corinthians 1:20', 'For all the promises of God in Him are Yes, and in Him Amen, to the glory of God through us.', 'NKJV', 'Promise'),
('0188b8e0-1234-7abc-8def-100000000447', '2 Corinthians 2:14', 'Now thanks be to God who always leads us in triumph in Christ, and through us diffuses the fragrance of His knowledge in every place.', 'NKJV', 'Victory'),
('0188b8e0-1234-7abc-8def-100000000448', '2 Corinthians 3:17', 'Now the Lord is the Spirit; and where the Spirit of the Lord is, there is liberty.', 'NKJV', 'Freedom'),
('0188b8e0-1234-7abc-8def-100000000449', '2 Corinthians 4:7', 'But we have this treasure in earthen vessels, that the excellence of the power may be of God and not of us.', 'NKJV', 'Power'),
('0188b8e0-1234-7abc-8def-100000000450', '2 Corinthians 4:8-9', 'We are hard-pressed on every side, yet not crushed; we are perplexed, but not in despair; persecuted, but not forsaken; struck down, but not destroyed.', 'NKJV', 'Endurance'),
('0188b8e0-1234-7abc-8def-100000000451', '2 Corinthians 4:17', 'For our light affliction, which is but for a moment, is working for us a far more exceeding and eternal weight of glory.', 'NKJV', 'Hope'),
('0188b8e0-1234-7abc-8def-100000000452', '2 Corinthians 4:18', 'While we do not look at the things which are seen, but at the things which are not seen. For the things which are seen are temporary, but the things which are not seen are eternal.', 'NKJV', 'Eternity'),
('0188b8e0-1234-7abc-8def-100000000453', '2 Corinthians 5:14', 'For the love of Christ compels us, because we judge thus: that if One died for all, then all died.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000454', '2 Corinthians 5:21', 'For He made Him who knew no sin to be sin for us, that we might become the righteousness of God in Him.', 'NKJV', 'Righteousness'),
('0188b8e0-1234-7abc-8def-100000000455', '2 Corinthians 6:2', 'For He says: "In an acceptable time I have heard you, And in the day of salvation I have helped you." Behold, now is the accepted time; behold, now is the day of salvation.', 'NKJV', 'Salvation'),
('0188b8e0-1234-7abc-8def-100000000456', '2 Corinthians 7:1', 'Therefore, having these promises, beloved, let us cleanse ourselves from all filthiness of the flesh and spirit, perfecting holiness in the fear of God.', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-100000000457', '2 Corinthians 8:9', 'For you know the grace of our Lord Jesus Christ, that though He was rich, yet for your sakes He became poor, that you through His poverty might become rich.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-100000000458', '2 Corinthians 9:8', 'And God is able to make all grace abound toward you, that you, always having all sufficiency in all things, may have an abundance for every good work.', 'NKJV', 'Provision'),
('0188b8e0-1234-7abc-8def-100000000459', '2 Corinthians 10:5', 'Casting down arguments and every high thing that exalts itself against the knowledge of God, bringing every thought into captivity to the obedience of Christ.', 'NKJV', 'Mindset'),
('0188b8e0-1234-7abc-8def-100000000460', '2 Corinthians 12:10', 'Therefore I take pleasure in infirmities, in reproaches, in needs, in persecutions, in distresses, for Christ’s sake. For when I am weak, then I am strong.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000461', '2 Corinthians 13:14', 'The grace of the Lord Jesus Christ, and the love of God, and the communion of the Holy Spirit be with you all. Amen.', 'NKJV', 'Blessing'),
('0188b8e0-1234-7abc-8def-100000000462', 'Galatians 1:10', 'For do I now persuade men, or God? Or do I seek to please men? For if I still pleased men, I would not be a bondservant of Christ.', 'NKJV', 'Pleasing God'),
('0188b8e0-1234-7abc-8def-100000000463', 'Galatians 2:21', 'I do not set aside the grace of God; for if righteousness comes through the law, then Christ died in vain.', 'NKJV', 'Grace'),
('0188b8e0-1234-7abc-8def-100000000464', 'Galatians 3:11', 'But that no one is justified by the law in the sight of God is evident, for "the just shall live by faith."', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000465', 'Galatians 3:26', 'For you are all sons of God through faith in Christ Jesus.', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000466', 'Galatians 4:6', 'And because you are sons, God has sent forth the Spirit of His Son into your hearts, crying out, "Abba, Father!"', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000467', 'Galatians 4:7', 'Therefore you are no longer a slave but a son, and if a son, then an heir of God through Christ.', 'NKJV', 'Inheritance'),
('0188b8e0-1234-7abc-8def-100000000468', 'Galatians 5:6', 'For in Christ Jesus neither circumcision nor uncircumcision avails anything, but faith working through love.', 'NKJV', 'Faith'),
('0188b8e0-1234-7abc-8def-100000000469', 'Galatians 5:14', 'For all the law is fulfilled in one word, even in this: "You shall love your neighbor as yourself."', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000470', 'Galatians 5:24', 'And those who are Christ’s have crucified the flesh with its passions and desires.', 'NKJV', 'Purity'),
('0188b8e0-1234-7abc-8def-100000000471', 'Galatians 5:25', 'If we live in the Spirit, let us also walk in the Spirit.', 'NKJV', 'Spirit'),
('0188b8e0-1234-7abc-8def-100000000472', 'Galatians 6:1', 'Brethren, if a man is overtaken in any trespass, you who are spiritual restore such a one in a spirit of gentleness, considering yourself lest you also be tempted.', 'NKJV', 'Restoration'),
('0188b8e0-1234-7abc-8def-100000000473', 'Galatians 6:3', 'For if anyone thinks himself to be something, when he is nothing, he deceives himself.', 'NKJV', 'Humility'),
('0188b8e0-1234-7abc-8def-100000000474', 'Galatians 6:4', 'But let each one examine his own work, and then he will have rejoicing in himself alone, and not in another.', 'NKJV', 'Self-Examination'),
('0188b8e0-1234-7abc-8def-100000000475', 'Galatians 6:7', 'Do not be deceived, God is not mocked; for whatever a man sows, that he will also reap.', 'NKJV', 'Sowing and Reaping'),
('0188b8e0-1234-7abc-8def-100000000476', 'Galatians 6:8', 'For he who sows to his flesh will of the flesh reap corruption, but he who sows to the Spirit will of the Spirit reap everlasting life.', 'NKJV', 'Spirit'),
('0188b8e0-1234-7abc-8def-100000000477', 'Galatians 6:14', 'But God forbid that I should boast except in the cross of our Lord Jesus Christ, by whom the world has been crucified to me, and I to the world.', 'NKJV', 'Boasting'),
('0188b8e0-1234-7abc-8def-100000000478', 'Ephesians 1:3', 'Blessed be the God and Father of our Lord Jesus Christ, who has blessed us with every spiritual blessing in the heavenly places in Christ.', 'NKJV', 'Blessing'),
('0188b8e0-1234-7abc-8def-100000000479', 'Ephesians 1:4', 'Just as He chose us in Him before the foundation of the world, that we should be holy and without blame before Him in love.', 'NKJV', 'Calling'),
('0188b8e0-1234-7abc-8def-100000000480', 'Ephesians 1:7', 'In Him we have redemption through His blood, the forgiveness of sins, according to the riches of His grace.', 'NKJV', 'Redemption'),
('0188b8e0-1234-7abc-8def-100000000481', 'Ephesians 1:13-14', 'In Him you also trusted, after you heard the word of truth, the gospel of your salvation; in whom also, having believed, you were sealed with the Holy Spirit of promise...', 'NKJV', 'Assurance'),
('0188b8e0-1234-7abc-8def-100000000482', 'Ephesians 2:13', 'But now in Christ Jesus you who once were far off have been brought near by the blood of Christ.', 'NKJV', 'Reconciliation'),
('0188b8e0-1234-7abc-8def-100000000483', 'Ephesians 2:14', 'For He Himself is our peace, who has made both one, and has broken down the middle wall of separation.', 'NKJV', 'Peace'),
('0188b8e0-1234-7abc-8def-100000000484', 'Ephesians 2:18', 'For through Him we both have access by one Spirit to the Father.', 'NKJV', 'Access'),
('0188b8e0-1234-7abc-8def-100000000485', 'Ephesians 2:19', 'Now, therefore, you are no longer strangers and foreigners, but fellow citizens with the saints and members of the household of God.', 'NKJV', 'Identity'),
('0188b8e0-1234-7abc-8def-100000000486', 'Ephesians 3:16', 'That He would grant you, according to the riches of His glory, to be strengthened with might through His Spirit in the inner man.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000487', 'Ephesians 3:17-18', 'That Christ may dwell in your hearts through faith; that you, being rooted and grounded in love, may be able to comprehend with all the saints what is the width and length and depth and height.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000488', 'Ephesians 3:19', 'To know the love of Christ which passes knowledge; that you may be filled with all the fullness of God.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000489', 'Ephesians 4:1', 'I, therefore, the prisoner of the Lord, beseech you to walk worthy of the calling with which you were called.', 'NKJV', 'Calling'),
('0188b8e0-1234-7abc-8def-100000000490', 'Ephesians 4:3', 'Endeavoring to keep the unity of the Spirit in the bond of peace.', 'NKJV', 'Unity'),
('0188b8e0-1234-7abc-8def-100000000491', 'Ephesians 4:23-24', 'And be renewed in the spirit of your mind, and that you put on the new man which was created according to God, in true righteousness and holiness.', 'NKJV', 'Renewal'),
('0188b8e0-1234-7abc-8def-100000000492', 'Ephesians 4:29', 'Let no corrupt word proceed out of your mouth, but what is good for necessary edification, that it may impart grace to the hearers.', 'NKJV', 'Speech'),
('0188b8e0-1234-7abc-8def-100000000493', 'Ephesians 4:30', 'And do not grieve the Holy Spirit of God, by whom you were sealed for the day of redemption.', 'NKJV', 'Spirit'),
('0188b8e0-1234-7abc-8def-100000000494', 'Ephesians 5:2', 'And walk in love, as Christ also has loved us and given Himself for us, an offering and a sacrifice to God for a sweet-smelling aroma.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000495', 'Ephesians 5:15-16', 'See then that you walk circumspectly, not as fools but as wise, redeeming the time, because the days are evil.', 'NKJV', 'Wisdom'),
('0188b8e0-1234-7abc-8def-100000000496', 'Ephesians 5:21', 'Submitting to one another in the fear of God.', 'NKJV', 'Humility'),
('0188b8e0-1234-7abc-8def-100000000497', 'Ephesians 6:10', 'Finally, my brethren, be strong in the Lord and in the power of His might.', 'NKJV', 'Strength'),
('0188b8e0-1234-7abc-8def-100000000498', 'Ephesians 6:18', 'Praying always with all prayer and supplication in the Spirit, being watchful to this end with all perseverance and supplication for all the saints.', 'NKJV', 'Prayer'),
('0188b8e0-1234-7abc-8def-100000000499', 'Philippians 1:9', 'And this I pray, that your love may abound still more and more in knowledge and all discernment.', 'NKJV', 'Love'),
('0188b8e0-1234-7abc-8def-100000000500', 'Philippians 1:27', 'Only let your conduct be worthy of the gospel of Christ, so that whether I come and see you or am absent, I may hear of your affairs, that you stand fast in one spirit...', 'NKJV', 'Conduct');
